mapper.update:
UPDATE report_version
SET report_id = #{reportId},
    version_num = #{versionNum},
    content_snapshot = #{contentSnapshot, jdbcType=OTHER, typeHandler=xenosoft.imldintelligence.common.mybatis.JsonNodeTypeHandler},
    change_summary = #{changeSummary},
    changed_by = #{changedBy}
WHERE tenant_id = #{tenantId}
  AND id = #{id}

mapper.delete:
